      { id:"xp7-d08a", part:7, question:"What is the hotel allowance for travel to San Francisco?", options:["USD 160 per night","USD 200 per night","USD 220 per night","USD 245 per night"], answer:2, explanation:"San Francisco is a Tier 1 city — 'the allowance is USD 220 per night.'" },
      { id:"xp7-d08b", part:7, question:"Why does Benjamin Hart's hotel claim exceed the allowance?", options:["He did not book through the approved portal","His nightly rate was USD 25 above the Tier 1 limit","He stayed an extra night without approval","He booked a luxury suite"], answer:1, explanation:"'USD 245 per night... which is USD 25 above the Tier 1 limit.'" },
      { id:"xp7-d08c", part:7, question:"Did Benjamin Hart fully comply with the policy for hotel pre-approval?", options:["Yes, verbal approval from a department head is sufficient","Yes, because he is a senior employee","No, because CFO approval was also required but not obtained","No, because he did not use the Tripwise portal"], answer:2, explanation:"Policy requires both department head AND CFO approval; Benjamin only obtained verbal approval from his department head." },
      { id:"xp7-d08d", part:7, question:"Why is the late checkout fee potentially reimbursable?", options:["Late checkout is always covered by policy","The client call required him to stay at the hotel past standard checkout","He had a medical appointment that afternoon","He was waiting for a delayed flight"], answer:1, explanation:"'I paid a USD 40 late checkout fee... to allow time for a client call that ran until 2:00 p.m.' This satisfies the 'business purposes' requirement in 4.3." }
